  payload.departures = parsed.departures
    .map(dep => ({
      departure_city: normalizeString(dep.departure_city),
      stock: normalizeNumber(dep.stock),
      flight_departure_time: normalizeString(dep.flight_departure_time),
      flight_arrival_time: normalizeString(dep.flight_arrival_time),
      return_flight_departure_time: normalizeString(dep.return_flight_departure_time),
      return_flight_arrival_time: normalizeString(dep.return_flight_arrival_time)
    }))
    .filter(dep =>
      dep.departure_city !== null ||
      dep.stock !== null ||
      dep.flight_departure_time !== null ||
      dep.flight_arrival_time !== null ||
      dep.return_flight_departure_time !== null ||
